  ('diplomatic-5118c8cd-moex-00330', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '依憲法規定及大法官解釋，人民基本權利之保障與限制，下列敘述何者錯誤？', '["憲法未明文列舉規定之自由權利的保障與限制，其依據為第22條及第23條", "基於人性尊嚴之理念，個人主體性及人格之自由發展，應受憲法保障", "凡憲法保障之基本權利，均僅得對國家主張", "憲法有明文列舉規定的基本權利之限制依據為憲法第23條"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
