  ('diplomatic-5118c8cd-moex-00332', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '關於行政院之財政權，下列敘述何者錯誤？', '["行政院於會計年度開始3個月前，應將下年度預算案提出於立法院", "行政院於會計年度結束後4個月內，應提出決算於監察院", "立法院對於行政院所提預算案，不得為增減支出之提議", "行政院對於司法院所提出之年度司法概算，不得刪減，但得加註意見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
